use actix_web::{web, App, HttpResponse, HttpServer};
use std::fs;
use std::path::{Path, PathBuf};

async fn serve_file(path: web::Path<String>) -> Result<HttpResponse, actix_web::Error> {
    let uploads_dir = "uploads";
    let full_path = Path::new(uploads_dir).join(&path);

    if !full_path.starts_with(uploads_dir) {
        return Err(actix_web::error::ErrorNotFound("File not found"));
    }

    match fs::read_to_string(full_path) {
        Ok(contents) => Ok(HttpResponse::Ok().content_type("text/plain").body(contents)),
        Err(_) => Err(actix_web::error::ErrorNotFound("File not found")),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/{filename:.*}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}